const topicOrder = ["BASICS", "ARRAY", "STRING", "SORTING", "SEARCHING", "HASHING", "MATH", "RECURSION", "BACKTRACKING", "LINKED LIST", "STACK", "QUEUE", "TREE", "BST", "DP", "GRAPH"];
let userProgress = JSON.parse(localStorage.getItem('vvp150Progress')) || {};
let interviewTimer = null;
let interviewStartTime = null;
let interviewQuestions = [];
let currentInterviewIndex = 0;

function saveProgress() {
    localStorage.setItem('vvp150Progress', JSON.stringify(userProgress));
}

function updateStats() {
    const solved = Object.values(userProgress).filter(q => q.solved).length;
    document.getElementById('solvedCount').textContent = solved;
    document.getElementById('progressPercent').textContent = Math.round((solved / questionsData.length) * 100) + '%';
}

function updateStreak() {
    const today = new Date().toDateString();
    const lastSolved = localStorage.getItem('lastSolvedDate');
    const streak = parseInt(localStorage.getItem('solveStreak') || '0');
    if (lastSolved === today) {
        document.getElementById('streakCount').textContent = streak + '🔥';
    } else {
        const yesterday = new Date(Date.now() - 86400000).toDateString();
        const newStreak = (lastSolved === yesterday) ? streak : 0;
        document.getElementById('streakCount').textContent = newStreak + '🔥';
    }
}

function recordSolve() {
    const today = new Date().toDateString();
    const lastSolved = localStorage.getItem('lastSolvedDate');
    const streak = parseInt(localStorage.getItem('solveStreak') || '0');
    if (lastSolved !== today) {
        const yesterday = new Date(Date.now() - 86400000).toDateString();
        const newStreak = (lastSolved === yesterday) ? streak + 1 : 1;
        localStorage.setItem('solveStreak', newStreak);
        localStorage.setItem('lastSolvedDate', today);
        updateStreak();
    }
}

function getTimeAgo(date) {
    const now = new Date();
    const solvedDate = new Date(date);
    const diffMs = now - solvedDate;
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);
    const diffWeeks = Math.floor(diffDays / 7);
    const diffMonths = Math.floor(diffDays / 30);
    if (diffMins < 1) return 'Just now';
    if (diffMins < 60) return `${diffMins} min${diffMins > 1 ? 's' : ''} ago`;
    if (diffHours < 24) return `${diffHours} hour${diffHours > 1 ? 's' : ''} ago`;
    if (diffDays < 7) return `${diffDays} day${diffDays > 1 ? 's' : ''} ago`;
    if (diffWeeks < 4) return `${diffWeeks} week${diffWeeks > 1 ? 's' : ''} ago`;
    if (diffMonths < 12) return `${diffMonths} month${diffMonths > 1 ? 's' : ''} ago`;
    return solvedDate.toLocaleDateString();
}

function renderTopicsSidebar() {
    const sidebar = document.getElementById('topicsSidebar');
    const topics = {};
    questionsData.forEach(q => {
        if (!topics[q.Topic]) topics[q.Topic] = 0;
        topics[q.Topic]++;
    });
    sidebar.innerHTML = '<h3 style="margin-bottom: 15px;">Topics</h3>';
    topicOrder.forEach(topic => {
        if (topics[topic]) {
            const div = document.createElement('div');
            div.className = 'topic-item';
            div.innerHTML = `<span>${topic}</span><span class="topic-count">${topics[topic]}</span>`;
            div.onclick = () => document.getElementById(`topic-${topic}`)?.scrollIntoView({ behavior: 'smooth' });
            sidebar.appendChild(div);
        }
    });
}

function renderQuestions(filter = {}) {
    const container = document.getElementById('questionsContainer');
    container.innerHTML = '';
    let filtered = questionsData.filter(q => {
        if (filter.search && !q['Question Name'].toLowerCase().includes(filter.search.toLowerCase())) return false;
        if (filter.topic && q.Topic !== filter.topic) return false;
        if (filter.difficulty && q.Difficulty !== filter.difficulty) return false;
        if (filter.pattern && q['Pattern Type'] !== filter.pattern) return false;
        if (filter.company && !q['Asked By'].includes(filter.company)) return false;
        return true;
    });
    const grouped = {};
    topicOrder.forEach(topic => { grouped[topic] = filtered.filter(q => q.Topic === topic); });
    topicOrder.forEach(topic => {
        if (grouped[topic].length === 0) return;
        const section = document.createElement('div');
        section.className = 'topic-section';
        section.id = `topic-${topic}`;
        const solved = grouped[topic].filter(q => userProgress[q.Sr]?.solved).length;
        const topicProgress = Math.round((solved / grouped[topic].length) * 100);
        section.innerHTML = `
            <div class="topic-header">
                <span>${topic}</span>
                <span class="topic-progress">${solved}/${grouped[topic].length} (${topicProgress}%)</span>
            </div>
            <div class="progress-bar"><div class="progress-fill" style="width: ${topicProgress}%"></div></div>
        `;
        grouped[topic].forEach(q => {
            const card = document.createElement('div');
            card.className = 'question-card';
            const progress = userProgress[q.Sr] || {};
            if (progress.solved) card.classList.add('solved');
            const timeSpent = progress.timeSpent ? `<span class="detail-tag">⏱️ ${Math.round(progress.timeSpent / 60)}min</span>` : '';
            const solvedDate = progress.solvedDate ? `<span class="detail-tag solved-date">✅ ${getTimeAgo(progress.solvedDate)}</span>` : '';
            card.innerHTML = `
                <div class="question-header">
                    <div class="checkbox-wrapper">
                        <input type="checkbox" class="checkbox" ${progress.solved ? 'checked' : ''} onchange="toggleSolved(${q.Sr})">
                    </div>
                    <span class="question-number">#${q.Sr}</span>
                    <span class="question-title">${q['Question Name']}</span>
                    <span class="difficulty ${q.Difficulty}">${q.Difficulty}</span>
                </div>
                <div class="question-details">
                    <span class="detail-tag">📌 ${q['Pattern Type']}</span>
                    <span class="detail-tag">🏢 ${q['Asked By']}</span>
                    <span class="detail-tag">⭐ ${q.Priority}</span>
                    ${timeSpent}${solvedDate}
                </div>
                <div class="question-actions">
                    <button class="btn btn-revision ${progress.revision ? 'active' : ''}" onclick="toggleRevision(${q.Sr})">${progress.revision ? '✓ Revision' : '+ Revision'}</button>
                    <button class="btn btn-secondary" onclick="openNoteModal(${q.Sr})">${progress.note ? '📝 Edit Note' : '+ Note'}</button>
                </div>
                ${progress.note ? `<div class="note-preview">📝 ${progress.note}</div>` : ''}
            `;
            section.appendChild(card);
        });
        container.appendChild(section);
    });
}

function toggleSolved(sr) {
    if (!userProgress[sr]) userProgress[sr] = {};
    const wasSolved = userProgress[sr].solved;
    userProgress[sr].solved = !wasSolved;
    if (!wasSolved) {
        userProgress[sr].solvedDate = new Date().toISOString();
        recordSolve();
    } else {
        delete userProgress[sr].solvedDate;
    }
    saveProgress();
    updateStats();
    renderQuestions(getCurrentFilters());
}

function toggleRevision(sr) {
    if (!userProgress[sr]) userProgress[sr] = {};
    userProgress[sr].revision = !userProgress[sr].revision;
    saveProgress();
    renderQuestions(getCurrentFilters());
}

let currentNoteSr = null;
function openNoteModal(sr) {
    currentNoteSr = sr;
    document.getElementById('noteText').value = userProgress[sr]?.note || '';
    document.getElementById('noteModal').style.display = 'block';
}

function closeNoteModal() {
    document.getElementById('noteModal').style.display = 'none';
    currentNoteSr = null;
}

document.querySelector('.close').onclick = closeNoteModal;
window.onclick = (e) => { if (e.target === document.getElementById('noteModal')) closeNoteModal(); };
document.getElementById('saveNote').onclick = () => {
    if (currentNoteSr) {
        const note = document.getElementById('noteText').value.trim();
        if (!userProgress[currentNoteSr]) userProgress[currentNoteSr] = {};
        userProgress[currentNoteSr].note = note;
        saveProgress();
        renderQuestions(getCurrentFilters());
        closeNoteModal();
    }
};

function getCurrentFilters() {
    return {
        search: document.getElementById('searchInput').value,
        topic: document.getElementById('topicFilter').value,
        difficulty: document.getElementById('difficultyFilter').value,
        pattern: document.getElementById('patternFilter').value,
        company: document.getElementById('companyFilter')?.value || ''
    };
}

function setupFilters() {
    const topics = [...new Set(questionsData.map(q => q.Topic))];
    const patterns = [...new Set(questionsData.map(q => q['Pattern Type']))].sort();
    const topicFilter = document.getElementById('topicFilter');
    topicOrder.forEach(topic => {
        if (topics.includes(topic)) {
            const opt = document.createElement('option');
            opt.value = topic;
            opt.textContent = topic;
            topicFilter.appendChild(opt);
        }
    });
    const patternFilter = document.getElementById('patternFilter');
    patterns.forEach(pattern => {
        const opt = document.createElement('option');
        opt.value = pattern;
        opt.textContent = pattern;
        patternFilter.appendChild(opt);
    });
    document.getElementById('searchInput').oninput = () => renderQuestions(getCurrentFilters());
    document.getElementById('topicFilter').onchange = () => renderQuestions(getCurrentFilters());
    document.getElementById('difficultyFilter').onchange = () => renderQuestions(getCurrentFilters());
    document.getElementById('patternFilter').onchange = () => renderQuestions(getCurrentFilters());
    document.getElementById('companyFilter')?.addEventListener('change', () => renderQuestions(getCurrentFilters()));
    document.getElementById('resetBtn').onclick = () => {
        document.getElementById('searchInput').value = '';
        document.getElementById('topicFilter').value = '';
        document.getElementById('difficultyFilter').value = '';
        document.getElementById('patternFilter').value = '';
        if(document.getElementById('companyFilter')) document.getElementById('companyFilter').value = '';
        renderQuestions();
    };
}

// Random Question
document.getElementById('randomBtn')?.addEventListener('click', () => {
    const unsolved = questionsData.filter(q => !userProgress[q.Sr]?.solved);
    if (unsolved.length === 0) {
        alert('🎉 Congratulations! You solved all questions!');
        return;
    }
    const random = unsolved[Math.floor(Math.random() * unsolved.length)];
    document.getElementById('randomQuestion').innerHTML = `
        <div style="padding: 20px 0;">
            <h3 style="color: #1a73e8; margin-bottom: 15px;">#${random.Sr} ${random['Question Name']}</h3>
            <div style="background: var(--bg-dark); padding: 15px; border-radius: 8px; margin: 15px 0;">
                <p style="margin: 8px 0;"><strong>📚 Topic:</strong> ${random.Topic}</p>
                <p style="margin: 8px 0;"><strong>📌 Pattern:</strong> ${random['Pattern Type']}</p>
                <p style="margin: 8px 0;"><strong>⚡ Difficulty:</strong> <span class="difficulty ${random.Difficulty}">${random.Difficulty}</span></p>
                <p style="margin: 8px 0;"><strong>⭐ Priority:</strong> ${random.Priority}</p>
                <p style="margin: 8px 0;"><strong>🏢 Asked By:</strong> ${random['Asked By']}</p>
            </div>
            <div style="display: flex; gap: 10px; margin-top: 20px;">
                <button class="btn btn-primary" onclick="markRandomSolved(${random.Sr})">✅ Mark Solved</button>
                <button class="btn btn-secondary" onclick="openRandomNote(${random.Sr})">📝 Add Note</button>
            </div>
        </div>
    `;
    document.getElementById('randomModal').style.display = 'block';
});

function closeRandomModal() {
    document.getElementById('randomModal').style.display = 'none';
}

function markRandomSolved(sr) {
    toggleSolved(sr);
    closeRandomModal();
}

function openRandomNote(sr) {
    closeRandomModal();
    openNoteModal(sr);
}

// Interview Mode
document.getElementById('interviewBtn')?.addEventListener('click', () => {
    const unsolved = questionsData.filter(q => !userProgress[q.Sr]?.solved && q.Priority === 'HIGH');
    if (unsolved.length === 0) {
        alert('Complete more HIGH priority questions first!');
        return;
    }
    interviewQuestions = unsolved.sort(() => Math.random() - 0.5).slice(0, 5);
    currentInterviewIndex = 0;
    document.getElementById('interviewModalTitle').textContent = '🎯 Interview Mode';
    document.getElementById('interviewModalDesc').style.display = 'block';
    document.getElementById('interviewButtons').style.display = 'block';
    document.getElementById('timerDisplay').style.display = 'block';
    document.getElementById('interviewModal').style.display = 'block';
    showInterviewQuestion();
});

function showInterviewQuestion() {
    if (currentInterviewIndex >= interviewQuestions.length) {
        alert('🎉 Interview practice completed!');
        closeInterviewModal();
        return;
    }
    const q = interviewQuestions[currentInterviewIndex];
    document.getElementById('interviewQuestion').innerHTML = `
        <div style="padding: 20px 0;">
            <h3 style="color: #1a73e8; margin-bottom: 15px;">Question ${currentInterviewIndex + 1}/${interviewQuestions.length}</h3>
            <h3>#${q.Sr} ${q['Question Name']}</h3>
            <div style="background: var(--bg-dark); padding: 15px; border-radius: 8px; margin: 15px 0;">
                <p style="margin: 8px 0;"><strong>📚 Topic:</strong> ${q.Topic}</p>
                <p style="margin: 8px 0;"><strong>📌 Pattern:</strong> ${q['Pattern Type']}</p>
                <p style="margin: 8px 0;"><strong>⚡ Difficulty:</strong> <span class="difficulty ${q.Difficulty}">${q.Difficulty}</span></p>
            </div>
        </div>
    `;
    interviewStartTime = Date.now();
    startInterviewTimer();
}

function startInterviewTimer() {
    clearInterval(interviewTimer);
    interviewTimer = setInterval(() => {
        const elapsed = Math.floor((Date.now() - interviewStartTime) / 1000);
        const mins = Math.floor(elapsed / 60);
        const secs = elapsed % 60;
        document.getElementById('timerDisplay').textContent = `⏱️ ${mins}:${secs.toString().padStart(2, '0')}`;
    }, 1000);
}

function nextInterviewQuestion() {
    const timeSpent = Math.floor((Date.now() - interviewStartTime) / 1000);
    const q = interviewQuestions[currentInterviewIndex];
    if (!userProgress[q.Sr]) userProgress[q.Sr] = {};
    userProgress[q.Sr].timeSpent = timeSpent;
    saveProgress();
    currentInterviewIndex++;
    showInterviewQuestion();
}

function closeInterviewModal() {
    clearInterval(interviewTimer);
    document.getElementById('interviewModal').style.display = 'none';
}

// Revision List
document.getElementById('revisionBtn')?.addEventListener('click', () => {
    const revisionList = questionsData.filter(q => userProgress[q.Sr]?.revision);
    if (revisionList.length === 0) {
        alert('No questions marked for revision yet!');
        return;
    }
    document.getElementById('topicFilter').value = '';
    document.getElementById('difficultyFilter').value = '';
    document.getElementById('patternFilter').value = '';
    if(document.getElementById('companyFilter')) document.getElementById('companyFilter').value = '';
    renderQuestions({ revision: true });
});

// Weak Topics
function showWeakTopics() {
    const topicStats = {};
    topicOrder.forEach(topic => {
        const topicQuestions = questionsData.filter(q => q.Topic === topic);
        const solved = topicQuestions.filter(q => userProgress[q.Sr]?.solved).length;
        const total = topicQuestions.length;
        topicStats[topic] = { solved, total, percent: Math.round((solved / total) * 100) };
    });
    const weak = Object.entries(topicStats).filter(([_, stats]) => stats.percent < 50).sort((a, b) => a[1].percent - b[1].percent);
    let content = '<div>';
    if (weak.length === 0) {
        content += '<p>🎉 Great job! No weak areas found. Keep practicing!</p>';
    } else {
        content += '<h3>Focus on these topics:</h3>';
        weak.forEach(([topic, stats]) => {
            content += `<div class="insight-card"><strong>${topic}</strong>: ${stats.solved}/${stats.total} (${stats.percent}%)<div class="progress-bar"><div class="progress-fill" style="width: ${stats.percent}%"></div></div></div>`;
        });
    }
    content += '</div>';
    document.getElementById('insightTitle').textContent = '📊 Your Weak Areas';
    document.getElementById('insightContent').innerHTML = content;
    document.getElementById('insightModal').style.display = 'block';
}

function showStreak() {
    const streak = parseInt(localStorage.getItem('solveStreak') || '0');
    const lastDate = localStorage.getItem('lastSolvedDate') || 'Never';
    const totalSolved = Object.values(userProgress).filter(q => q.solved).length;
    const content = `<div class="insight-card"><h3>🔥 Current Streak: ${streak} days</h3><p>Last solved: ${lastDate}</p><p>Total solved: ${totalSolved}/150</p><p>Keep solving daily to maintain your streak!</p></div>`;
    document.getElementById('insightTitle').textContent = '🔥 Your Streak';
    document.getElementById('insightContent').innerHTML = content;
    document.getElementById('insightModal').style.display = 'block';
}

function closeInsightModal() {
    document.getElementById('insightModal').style.display = 'none';
}

// Export PDF
document.getElementById('exportBtn')?.addEventListener('click', () => {
    const questionsWithNotes = questionsData.filter(q => userProgress[q.Sr]?.note);
    if (questionsWithNotes.length === 0) {
        alert('No notes to export! Add notes to questions first.');
        return;
    }
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();
    let yPos = 20;
    const pageHeight = doc.internal.pageSize.height;
    const margin = 20;
    const lineHeight = 7;
    doc.setFontSize(18);
    doc.setFont(undefined, 'bold');
    doc.text('VVP 150 DSA - My Notes', margin, yPos);
    yPos += 10;
    doc.setFontSize(10);
    doc.setFont(undefined, 'normal');
    doc.text(`Total Notes: ${questionsWithNotes.length} | Date: ${new Date().toLocaleDateString()}`, margin, yPos);
    yPos += 15;
    const grouped = {};
    topicOrder.forEach(topic => { grouped[topic] = questionsWithNotes.filter(q => q.Topic === topic); });
    topicOrder.forEach(topic => {
        if (grouped[topic].length === 0) return;
        if (yPos > pageHeight - 40) { doc.addPage(); yPos = 20; }
        doc.setFontSize(14);
        doc.setFont(undefined, 'bold');
        doc.setTextColor(26, 115, 232);
        doc.text(`${topic} (${grouped[topic].length} notes)`, margin, yPos);
        yPos += 10;
        grouped[topic].forEach((q, index) => {
            const progress = userProgress[q.Sr];
            if (yPos > pageHeight - 60) { doc.addPage(); yPos = 20; }
            doc.setFontSize(11);
            doc.setFont(undefined, 'bold');
            doc.setTextColor(0, 0, 0);
            doc.text(`${index + 1}. #${q.Sr} ${q['Question Name']}`, margin, yPos);
            yPos += lineHeight;
            doc.setFontSize(9);
            doc.setFont(undefined, 'normal');
            doc.setTextColor(100, 100, 100);
            doc.text(`Pattern: ${q['Pattern Type']} | Difficulty: ${q.Difficulty} | Priority: ${q.Priority}`, margin + 5, yPos);
            yPos += lineHeight;
            doc.text(`Companies: ${q['Asked By']}`, margin + 5, yPos);
            yPos += lineHeight + 2;
            doc.setFontSize(10);
            doc.setTextColor(0, 0, 0);
            doc.setFont(undefined, 'normal');
            const noteLines = doc.splitTextToSize(progress.note, 170);
            noteLines.forEach(line => {
                if (yPos > pageHeight - 20) { doc.addPage(); yPos = 20; }
                doc.text(line, margin + 5, yPos);
                yPos += lineHeight;
            });
            yPos += 5;
            doc.setDrawColor(200, 200, 200);
            doc.line(margin, yPos, 190, yPos);
            yPos += 8;
        });
        yPos += 5;
    });
    const totalPages = doc.internal.getNumberOfPages();
    for (let i = 1; i <= totalPages; i++) {
        doc.setPage(i);
        doc.setFontSize(8);
        doc.setTextColor(150, 150, 150);
        doc.text(`Page ${i} of ${totalPages} | VVP 150 DSA Tracker`, margin, pageHeight - 10);
    }
    const fileName = `VVP_DSA_Notes_${new Date().toISOString().split('T')[0]}.pdf`;
    doc.save(fileName);
    alert(`✅ PDF exported successfully!\nFile: ${fileName}\nTotal notes: ${questionsWithNotes.length}`);
});

updateStats();
updateStreak();
renderTopicsSidebar();
setupFilters();
renderQuestions();
